mapper.update:
UPDATE alliance_boss
SET max_hp = #{maxHp}, current_hp = #{currentHp}
WHERE id = #{id}

UPDATE alliance_boss
SET status = #{toStatus}
WHERE id = #{id}
  AND status = #{fromStatus}

mapper.select:
SELECT id, user_id AS userId, action_type AS actionType,
       damage, feed_amount AS feedAmount, created_at AS createdAt
FROM alliance_boss_record
WHERE server_id = #{serverId}
  AND alliance_id = #{allianceId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT user_id AS userId, SUM(damage) AS totalDamage,
       COUNT(*) AS attackCount
FROM alliance_boss_record
WHERE action_type = 'attack'
  AND server_id = #{serverId}
  AND alliance_id = #{allianceId}
GROUP BY user_id
ORDER BY totalDamage DESC
LIMIT #{limit}

SELECT user_id AS userId, SUM(damage) AS totalDamage,
       COUNT(*) AS attackCount
FROM alliance_boss_record
WHERE action_type = 'attack'
  AND server_id = #{serverId}
  AND alliance_id = #{allianceId}
  AND cycle_id = #{cycleId}
  AND created_at > IFNULL((
      SELECT MAX(created_at)
      FROM alliance_boss_record
      WHERE server_id = #{serverId}
        AND alliance_id = #{allianceId}
        AND action_type = 'boss_cycle_reset'
  ), '1970-01-01 00:00:00')
GROUP BY user_id
ORDER BY totalDamage DESC
LIMIT #{limit}

SELECT user_id AS userId, SUM(feed_amount) AS totalFeed,
       COUNT(*) AS feedTimes
FROM alliance_boss_record
WHERE action_type IN ('feed', 'feed_equip')
  AND server_id = #{serverId}
  AND alliance_id = #{allianceId}
  AND cycle_id = #{cycleId}
  AND created_at > IFNULL((
      SELECT MAX(created_at)
      FROM alliance_boss_record
      WHERE server_id = #{serverId}
        AND alliance_id = #{allianceId}
        AND action_type = 'boss_cycle_reset'
  ), '1970-01-01 00:00:00')
GROUP BY user_id
ORDER BY totalFeed DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM alliance_boss_record
WHERE server_id = #{serverId}
  AND alliance_id = #{allianceId}
  AND cycle_id = #{cycleId}
  AND action_type = #{actionType}

SELECT COUNT(*)
FROM alliance_boss_record
WHERE user_id = #{userId}
  AND server_id = #{serverId}
  AND alliance_id = #{allianceId}
  AND cycle_id = #{cycleId}
  AND action_type = 'attack'
  AND created_at > IFNULL((
      SELECT MAX(created_at)
      FROM alliance_boss_record
      WHERE server_id = #{serverId}
        AND alliance_id = #{allianceId}
        AND action_type = 'boss_cycle_reset'
  ), '1970-01-01 00:00:00')
